from typing import Set, List, Optional, Iterable, Tuple

from geosat.cloud import PointCloud, pyvoxels
from geosat.cloud.pyvoxels import VoxelDict3D
from geosat.cloud_ext.cppraster import RasterFunctionType
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata


def _iter_interior_voxels(voxels: VoxelDict3D) -> Iterable[Tuple[int, int, int]]:
    voxels_xy = pyvoxels.project_voxels_to_2d(voxels)
    for (x, y), z_list in voxels_xy.items():
        for z in z_list[1:-1]:
            yield x, y, z


class InteriorClassifier(Classifier):
    """Given a column of voxels, this classifier will declassify the points that
    are between the top and the bottom voxels. It is useful to remove the interior of
    a forest for aerial acquisitions.
    """

    def __init__(
        self,
        gsd=0.25,
        stage_name: Optional[str] = None,
        output_class: str = "unclassified",
    ):
        super().__init__(stage_name)
        self.gsd = gsd
        self.output_class = output_class

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option("gsd", "Size of the voxels", type_cast=float, required=False),
            Option(
                "output_class",
                description="The class to use for the points of the interior",
                type_cast=str,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if len(cloud) == 0:
            return (cloud,)
        class_code = pipeline_metadata.classification_codes[self.output_class]
        voxels = pyvoxels.voxelize_cloud(
            cloud, self.gsd, raster_fn=RasterFunctionType.PixelIsGlobal
        )
        point_indices = [
            point_index
            for voxel in _iter_interior_voxels(voxels)
            for point_index in voxels[voxel]
        ]
        cloud.classification[point_indices] = class_code
        return (cloud,)

    def input_classes(self) -> Set[str]:
        return set()

    def output_classes(self) -> Set[str]:
        return {self.output_class}
